module decoder_3to8(
    input en,         // Enable signal.
    input [2:0] a,    // 3-bit binary input.
    output [7:0] y    // 8-bit one-hot output.
);

reg [7:0] z_q;

// Decoder logic
always @(*) begin
    if (en) begin
        case (a)
            3'b000: z_q = 8'b00000001;
            3'b001: z_q = 8'b00000010;
            3'b010: z_q = 8'b00000100;
            3'b011: z_q = 8'b00001000;
            3'b100: z_q = 8'b00010000;
            3'b101: z_q = 8'b00100000;
            3'b110: z_q = 8'b01000000;
            3'b111: z_q = 8'b10000000;
            default: z_q = 8'b00000000;
        endcase
    end else begin
        z_q = 8'b00000000;
    end
end

assign y = z_q;

endmodule
